class Solution(object):
    def maximizeSquareArea(self, m, n, hFences, vFences):
        """
        :type m: int
        :type n: int
        :type hFences: List[int]
        :type vFences: List[int]
        :rtype: int
        """
        # pre-process
        MODULO = 10 ** 9 + 7
        # helper function
        def process(arr):
            l = len(arr)
            gaps = list()
            for x in range(1, l):
                gaps.append(arr[x] - arr[x - 1])
            return gaps

        def combine(arr):
            L = len(arr)
            presums = [0]
            for num in arr:
                presums.append(presums[-1] + num)

            combinations = set()
            for step in range(L):
                for x in range(L - step):
                    combination = presums[x + step + 1] - presums[x]
                    combinations.add(combination)
            return combinations

        # process
        hFences, vFences = sorted([1] + hFences + [m]), sorted([1] + vFences + [n])
        chFences, cvFences = combine(process(hFences)), combine(process(vFences))
        # print(chFences)
        # print(cvFences)

        ans = -1
        for chFence in sorted(chFences, reverse=True):
            if chFence in cvFences:
                ans = (chFence * chFence) %MODULO
                break
        return ans


